import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { MessageSquare, LayoutGrid, List, Settings, Search, X } from 'lucide-react';
import { useTaskStore } from './useTaskStore';
import { useVoice } from './useVoice';
import { parseTask } from './taskParser';
import { simulateAISync, simulateOCR } from './aiIntelligence';
import { TalkView } from './components/TalkView';
import { BubblesView } from './components/BubblesView';
import { BubbleDetailModal } from './components/BubbleDetailModal';
import { SettingsModal } from './components/SettingsModal';
import { LoginView } from './components/LoginView';
import { ScanModal } from './components/ScanModal';
import { SyncHubModal } from './components/SyncHubModal';
import { NotificationManager } from './components/NotificationManager';
import { getTranslation } from './translations';
import { ShareModal } from './components/ShareModal';
import './App.css';

// Screen order for swipe navigation
const VIEWS = ['talk', 'bubbles'];
const VIEWMODES = ['grid', 'list'];

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(localStorage.getItem('bp_logged_in') === 'true');
  const [activeView, setActiveView] = useState('talk'); // talk, bubbles
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [showSettings, setShowSettings] = useState(false);
  const [toast, setToast] = useState(null);
  const [syncStatus, setSyncStatus] = useState(null);
  const [pendingTask, setPendingTask] = useState(null);
  const [searchMode, setSearchMode] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState('grid');
  const [showScanModal, setShowScanModal] = useState(false);
  const [showSyncHubModal, setShowSyncHubModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [shareTasks, setShareTasks] = useState([]);
  const [isShareMode, setIsShareMode] = useState(false);
  const voiceRef = useRef(null);

  const {
    tasks, routines, categorySettings, userSettings,
    addTask, setTasks, updateTask, toggleTaskStatus, postponeTask, deleteTask, toggleReminder,
    updateUserSettings, toggleCategoryRoutines, updateRoutines
  } = useTaskStore();

  const handleLogin = (user) => {
    setIsLoggedIn(true);
    localStorage.setItem('bp_logged_in', 'true');
    setToast(`Welcome back, ${user}!`);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    localStorage.removeItem('bp_logged_in');
    setShowSettings(false);
  };

  useEffect(() => {
    document.documentElement.style.setProperty('--user-accent', userSettings.accentColor);
    document.documentElement.style.setProperty('--user-font', userSettings.fontFamily);

    if (userSettings.theme === 'light') {
      document.documentElement.classList.add('light-theme');
    } else {
      document.documentElement.classList.remove('light-theme');
    }
  }, [userSettings]);

  const handleTaskResult = useCallback((text) => {
    const parsed = parseTask(text);
    const newTask = {
      ...parsed,
      id: Date.now().toString(),
      createdAt: Date.now(),
      status: 'open',
    };
    setPendingTask(newTask);
    if (voiceRef.current) voiceRef.current.setStatus('ready');
  }, []); // No circular dependency

  const handleConfirmTask = useCallback((confirmedTask) => {
    addTask(confirmedTask);
    setPendingTask(null);
    setToast(getTranslation(userSettings.language, 'taskAdded')); // Adding this key to translations if missing
    setActiveView('bubbles');

    if (!confirmedTask.dueAt) {
      voiceRef.current?.scheduleDeadlineAsk(confirmedTask);
    }
  }, [addTask]);

  const handleDeadlineResult = useCallback((text) => {
    if (/нет|не знаю|без срока|пока нет/i.test(text)) {
      setToast('Отложено');
      if (voiceRef.current?.clarifyingTaskId) voiceRef.current.stopAllTimers(voiceRef.current.clarifyingTaskId);
      voiceRef.current?.setStatus('ready');
      return;
    }

    if (/да|хочу|давай|уточним/i.test(text) && text.length < 15) {
      voiceRef.current?.speak("Слушаю срок.", true);
      return;
    }

    const parsed = parseTask(text);
    if (parsed.dueAt) {
      // Prioritize the task we are currently clarifying
      const lastTask = voiceRef.current?.clarifyingTaskId
        ? tasks.find(t => t.id === voiceRef.current.clarifyingTaskId)
        : [...tasks].reverse().find(t => !t.dueAt);

      if (lastTask) {
        updateTask(lastTask.id, { dueAt: parsed.dueAt });
        setToast('Срок установлен!');
        voiceRef.current?.stopAllTimers(lastTask.id);
      }
      voiceRef.current?.setStatus('ready');
    } else {
      // If it's a deadline prompt but we didn't catch a date, 
      // maybe the user said something else. Don't get stuck in 'processing'.
      voiceRef.current?.setStatus('ready');
    }
  }, [tasks, updateTask]);

  const voice = useVoice({
    onTaskResult: handleTaskResult,
    onDeadlineResult: handleDeadlineResult,
    enableWakeWord: userSettings.voiceActivation,
    language: userSettings.language || 'en'
  });

  useEffect(() => {
    voiceRef.current = voice;
  }, [voice]);

  const handleManualInput = useCallback((text) => {
    if (voiceRef.current?.status === 'clarifying') {
      handleDeadlineResult(text);
      voiceRef.current?.setStatus('ready');
    } else {
      handleTaskResult(text);
    }
  }, [handleTaskResult, handleDeadlineResult]);

  const handleSmartSync = useCallback(() => {
    setShowSyncHubModal(true);
  }, []);

  const handleSyncHubResults = useCallback((newTasks) => {
    newTasks.forEach(t => {
      addTask({
        ...t,
        id: `sync-${Date.now()}-${Math.random()}`,
        createdAt: Date.now(),
        status: 'open'
      });
    });
    setToast(`Sync complete: ${newTasks.length} tasks added!`);
    setActiveView('bubbles');
  }, [addTask]);

  const handleOCRScan = useCallback(() => {
    setShowScanModal(true);
  }, []);

  const handleScanResult = useCallback((text) => {
    const parsed = parseTask(text);
    addTask({
      ...parsed,
      id: `ocr-${Date.now()}`,
      createdAt: Date.now(),
      status: 'open'
    });
    setToast('OCR: Task detected!');
    setShowScanModal(false);
    setActiveView('bubbles');
  }, [addTask]);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  // Auto-delete tasks that have been 'done' for more than 1 hour
  useEffect(() => {
    const ONE_HOUR = 60 * 60 * 1000;
    const interval = setInterval(() => {
      const now = Date.now();
      const toKeep = tasks.filter(t => {
        if (t.status !== 'done') return true;
        const completedAt = t.completedAt || t.updatedAt;
        if (!completedAt) return true;
        return (now - completedAt) < ONE_HOUR;
      });
      if (toKeep.length !== tasks.length) {
        setTasks(toKeep);
      }
    }, 60 * 1000); // check every minute
    return () => clearInterval(interval);
  }, [tasks, setTasks]);

  const handleShareTasks = useCallback((tasksToShare) => {
    setShareTasks(tasksToShare);
    setShowShareModal(true);
  }, []);

  // Swipe gesture navigation
  const swipeStartX = useRef(null);
  const swipeStartY = useRef(null);
  const handleTouchStart = useCallback((e) => {
    swipeStartX.current = e.touches[0].clientX;
    swipeStartY.current = e.touches[0].clientY;
  }, []);
  const handleTouchEnd = useCallback((e) => {
    if (swipeStartX.current === null) return;
    const dx = e.changedTouches[0].clientX - swipeStartX.current;
    const dy = e.changedTouches[0].clientY - swipeStartY.current;
    swipeStartX.current = null;
    // Only register horizontal swipes (must be more horizontal than vertical)
    if (Math.abs(dx) < 60 || Math.abs(dy) > Math.abs(dx) * 0.8) return;
    if (dx < 0) {
      // swipe left → next screen
      if (activeView === 'talk') { setActiveView('bubbles'); setViewMode('grid'); }
      else if (activeView === 'bubbles' && viewMode === 'grid') setViewMode('list');
    } else {
      // swipe right → previous screen
      if (activeView === 'bubbles' && viewMode === 'list') setViewMode('grid');
      else if (activeView === 'bubbles') { setActiveView('talk'); setIsShareMode(false); }
    }
  }, [activeView, viewMode]);

  if (!isLoggedIn) {
    return (
      <div className="app-container">
        <div className="phone-frame glass-container">
          <div className="notch" />
          <LoginView onLogin={handleLogin} />
        </div>
      </div>
    );
  }

  return (
    <div className="app-container">
      <div className="phone-frame glass-container">
        <div className="notch" />

        <div className="bg-blobs">
          <motion.div
            animate={{ scale: [1, 1.2, 1], x: [0, 20, 0] }}
            transition={{ duration: 10, repeat: Infinity }}
            className="bg-blob blob-1"
          />
          <motion.div
            animate={{ scale: [1, 1.3, 1], y: [0, 30, 0] }}
            transition={{ duration: 15, repeat: Infinity, delay: 2 }}
            className="bg-blob blob-2"
          />
          <motion.div
            animate={{ scale: [1, 1.1, 1], x: [0, -20, 0] }}
            transition={{ duration: 12, repeat: Infinity, delay: 5 }}
            className="bg-blob blob-3"
          />
        </div>

        <header className="app-header">
          {activeView === 'talk' && (
            <div className="brand" onClick={() => setActiveView('talk')} style={{ cursor: 'pointer' }}>
              <div className="logo-bubble-container">
                <div className="logo-bubble-blob">
                  <div className="logo-inner-glow" />
                  <span className="logo-char">B</span>
                </div>
              </div>
              <div className="brand-text">
                <h1 className="connected-text">ubble<span>Planner</span></h1>
              </div>
            </div>
          )}
          <div className="header-actions">
            <div className="action-btns-row">
              <button className={`icon-btn ${searchMode ? 'active' : ''}`} onClick={() => setSearchMode(!searchMode)} title="Search"><Search size={18} /></button>
              <button className="icon-btn" onClick={() => setShowSettings(true)} title="Settings"><Settings size={18} /></button>
            </div>
            <div
              className="header-stats"
              onClick={() => { setActiveView('bubbles'); setViewMode('list'); }}
              style={{ cursor: 'pointer' }}
              title={getTranslation(userSettings.language, 'tasks')}
            >
              <span className="stat-item done">{getTranslation(userSettings.language, 'done')}: {tasks.filter(t => t.status === 'done').length}</span>
              <span className="stat-item active-tasks">{getTranslation(userSettings.language, 'pending')}: {tasks.filter(t => t.status !== 'done').length}</span>
            </div>
          </div>
        </header>

        <AnimatePresence>
          {searchMode && (
            <motion.div
              initial={{ y: -20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: -20, opacity: 0 }}
              style={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                zIndex: 1100,
                background: 'rgba(13, 13, 13, 0.8)',
                backdropFilter: 'blur(20px)',
                borderBottom: '1px solid var(--border-color)',
                padding: '8px 16px',
                paddingTop: '35px' // Space for notch
              }}
            >
              <div className="search-input-wrapper" style={{ position: 'relative', display: 'flex', alignItems: 'center' }}>
                <Search size={16} style={{ position: 'absolute', left: '12px', color: 'var(--accent-primary)', opacity: 0.8 }} />
                <input
                  autoFocus
                  type="text"
                  placeholder={getTranslation(userSettings.language, 'searchPlaceholder')}
                  value={searchQuery}
                  onChange={(e) => {
                    setSearchQuery(e.target.value);
                    if (activeView !== 'bubbles') setActiveView('bubbles');
                  }}
                  className="global-search-input"
                  style={{
                    width: '100%',
                    background: 'rgba(255,255,255,0.05)',
                    border: '1px solid rgba(255,255,255,0.1)',
                    borderRadius: '12px',
                    padding: '8px 35px 8px 35px',
                    color: '#fff',
                    fontSize: '0.95rem',
                    outline: 'none'
                  }}
                />
                <button
                  onClick={() => { setSearchQuery(''); setSearchMode(false); }}
                  style={{ position: 'absolute', right: '10px', background: 'transparent', border: 'none', color: 'rgba(255,255,255,0.5)', cursor: 'pointer', display: 'flex', alignItems: 'center' }}
                >
                  <X size={12} />
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <main className="main-content" onTouchStart={handleTouchStart} onTouchEnd={handleTouchEnd}>
          <AnimatePresence mode="wait">
            {activeView === 'talk' ? (
              <TalkView
                key="talk"
                status={voice.status}
                transcript={voice.transcript}
                isListening={voice.isListening}
                onToggleMic={voice.toggleListening}
                onManualTask={handleManualInput}
                onSmartSync={handleSmartSync}
                onOCRScan={handleOCRScan}
                syncStatus={syncStatus}
                pendingTask={pendingTask}
                onConfirmTask={handleConfirmTask}
                onCancelPending={() => setPendingTask(null)}
                language={userSettings.language}
              />
            ) : (
              <BubblesView
                key="bubbles"
                tasks={tasks}
                searchQuery={searchQuery}
                onBubbleClick={(b) => setSelectedCategory(b.name)}
                onToggleTask={toggleTaskStatus}
                onUpdateTask={updateTask}
                onDeleteTask={deleteTask}
                onShareTasks={handleShareTasks}
                onToggleReminder={toggleReminder}
                clarifyingTaskId={voice.clarifyingTaskId}
                onClose={() => setActiveView('talk')}
                viewMode={viewMode}
                onViewModeChange={setViewMode}
                isShareMode={isShareMode}
                onToggleShareMode={(val) => setIsShareMode(val !== undefined ? val : !isShareMode)}
                onSetTasks={setTasks}
                onToggleSearch={() => setSearchMode(!searchMode)}
                onSearchChange={setSearchQuery}
                onAddTask={addTask}
                onToggleMic={voice.toggleListening}
                language={userSettings.language}
              />
            )}
          </AnimatePresence>
        </main>

        <footer className="bottom-nav">
          <button
            className={`nav-item ${activeView === 'talk' ? 'active' : ''}`}
            onClick={() => { setActiveView('talk'); setIsShareMode(false); }}
          >
            <MessageSquare size={22} />
            <span>{getTranslation(userSettings.language, 'talk')}</span>
          </button>
          <button
            className={`nav-item ${activeView === 'bubbles' && viewMode === 'grid' ? 'active' : ''}`}
            onClick={() => { setActiveView('bubbles'); setViewMode('grid'); setIsShareMode(false); }}
          >
            <LayoutGrid size={22} />
            <span>{getTranslation(userSettings.language, 'bubbles')}</span>
          </button>
          <button
            className={`nav-item ${activeView === 'bubbles' && viewMode === 'list' ? 'active' : ''}`}
            onClick={() => { setActiveView('bubbles'); setViewMode('list'); setIsShareMode(false); }}
          >
            <List size={22} />
            <span>{getTranslation(userSettings.language, 'list')}</span>
          </button>
        </footer>

        <AnimatePresence>
          {selectedCategory && tasks.some(t => t.category === selectedCategory) && (
            <BubbleDetailModal
              bubble={{
                name: selectedCategory,
                tasks: tasks.filter(t => t.category === selectedCategory)
              }}
              onClose={() => setSelectedCategory(null)}
              onToggleTask={toggleTaskStatus}
              onPostponeTask={postponeTask}
              onShareTask={handleShareTasks}
              onUpdateTask={updateTask}
              onDeleteTask={deleteTask}
              onSetTasks={setTasks}
              allTasks={tasks}
              onAddTask={addTask}
              onToggleReminder={toggleReminder}
              onToggleMic={voice.toggleListening}
              clarifyingTaskId={voice.clarifyingTaskId}
              routines={routines}
              showRoutines={userSettings.enableDailyRoutines}
              onToggleRoutines={() => updateUserSettings({ enableDailyRoutines: !userSettings.enableDailyRoutines })}
              language={userSettings.language}
            />
          )}

          {showSettings && (
            <SettingsModal
              settings={userSettings}
              routines={routines}
              onUpdate={updateUserSettings}
              onUpdateRoutines={updateRoutines}
              onClose={() => setShowSettings(false)}
              onLogout={handleLogout}
            />
          )}

          {showScanModal && (
            <ScanModal
              onClose={() => setShowScanModal(false)}
              onScanComplete={handleScanResult}
            />
          )}

          {showSyncHubModal && (
            <SyncHubModal
              onClose={() => setShowSyncHubModal(false)}
              onSync={handleSyncHubResults}
            />
          )}

          {showShareModal && (
            <ShareModal
              isOpen={showShareModal}
              onClose={() => setShowShareModal(false)}
              tasks={shareTasks}
              language={userSettings.language}
            />
          )}

          {toast && (
            <motion.div
              initial={{ y: 50, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              exit={{ y: 50, opacity: 0 }}
              className="toast-notification"
              style={{
                position: 'absolute', bottom: '100px', left: '24px', right: '24px',
                background: 'rgba(255,255,255,0.1)', backdropFilter: 'blur(20px)',
                padding: '12px 20px', borderRadius: '16px', border: '1px solid rgba(255,255,255,0.1)',
                color: '#fff', textAlign: 'center', zIndex: 1000, pointerEvents: 'none'
              }}
            >
              {toast}
            </motion.div>
          )}
        </AnimatePresence>
        <NotificationManager tasks={tasks} />
      </div>
    </div>
  );
}

export default App;

