import { useReducer, useCallback } from 'react';

const TASKS_KEY = 'bubble_planner_tasks';
const ROUTINES_KEY = 'bubble_planner_routines';
const SETTINGS_KEY = 'bubble_planner_settings';
const CAT_SETTINGS_KEY = 'bubble_planner_cat_settings';

const defaultRoutines = [
    { id: 'r1', text: 'Wake up', icon: 'Sun', startTime: '06:00', endTime: '07:00' },
    { id: 'r2', text: 'Brush teeth', icon: 'Activity', startTime: '07:15', endTime: '07:30' },
    { id: 'r3', text: 'Eat breakfast', icon: 'Coffee', startTime: '08:00', endTime: '08:30' },
    { id: 'r4', text: 'Drink water', icon: 'Droplets', startTime: '10:00', endTime: '10:15' },
    { id: 'r5', text: 'Hug', icon: 'Heart', startTime: '18:00', endTime: '18:15' },
    { id: 'r6', text: 'Call', icon: 'Phone', startTime: '20:00', endTime: '21:00' },
];

const initialState = {
    tasks: JSON.parse(localStorage.getItem(TASKS_KEY)) || [],
    routines: JSON.parse(localStorage.getItem(ROUTINES_KEY)) || defaultRoutines,
    categorySettings: JSON.parse(localStorage.getItem(CAT_SETTINGS_KEY)) || {},
    userSettings: JSON.parse(localStorage.getItem(SETTINGS_KEY)) || {
        accentColor: '#8a2be2',
        fontFamily: 'Outfit, sans-serif',
        language: 'en',
        theme: 'dark'
    },
};

function taskReducer(state, action) {
    let newState;
    switch (action.type) {
        case 'ADD_TASK':
            newState = { ...state, tasks: [...state.tasks, { ...action.payload, reminders: [5, 30, 60] }] };
            break;
        case 'SET_TASKS':
            newState = { ...state, tasks: action.payload };
            break;
        case 'UPDATE_TASK':
            newState = {
                ...state,
                tasks: state.tasks.map(t => t.id === action.payload.id ? { ...t, ...action.payload.updates } : t)
            };
            break;
        case 'DELETE_TASK':
            newState = { ...state, tasks: state.tasks.filter(t => t.id !== action.payload) };
            break;
        case 'TOGGLE_STATUS':
            newState = {
                ...state,
                tasks: state.tasks.map(t => {
                    if (t.id !== action.payload) return t;
                    const nextStatus = t.status === 'done' ? 'open' : 'done';
                    return {
                        ...t,
                        status: nextStatus,
                        completedAt: nextStatus === 'done' ? Date.now() : null,
                    };
                })
            };
            break;
        case 'POSTPONE_TASK':
            newState = {
                ...state,
                tasks: state.tasks.map(t =>
                    t.id === action.payload.id ? { ...t, status: 'open', dueAt: action.payload.dueAt || (Date.now() + 86400000 * 7) } : t
                )
            };
            break;
        case 'TOGGLE_REMINDER':
            newState = {
                ...state,
                tasks: state.tasks.map(t => {
                    if (t.id !== action.payload.id) return t;
                    const reminders = t.reminders || [];
                    const offset = action.payload.offset;
                    const nextReminders = reminders.includes(offset)
                        ? reminders.filter(r => r !== offset)
                        : [...reminders, offset];
                    return { ...t, reminders: nextReminders };
                })
            };
            break;
        case 'UPDATE_ROUTINES':
            newState = { ...state, routines: action.payload };
            break;
        case 'TOGGLE_CAT_ROUTINES':
            const { category } = action.payload;
            newState = {
                ...state,
                categorySettings: {
                    ...state.categorySettings,
                    [category]: {
                        ...state.categorySettings[category],
                        showRoutines: !state.categorySettings[category]?.showRoutines
                    }
                }
            };
            break;
        case 'UPDATE_USER_SETTINGS':
            newState = { ...state, userSettings: { ...state.userSettings, ...action.payload } };
            break;
        default:
            return state;
    }
    localStorage.setItem(TASKS_KEY, JSON.stringify(newState.tasks.map(t => ({ ...t, reminders: t.reminders || [5, 30, 60] }))));
    localStorage.setItem(ROUTINES_KEY, JSON.stringify(newState.routines));
    localStorage.setItem(CAT_SETTINGS_KEY, JSON.stringify(newState.categorySettings));
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(newState.userSettings));
    return newState;
}

export function useTaskStore() {
    const [state, dispatch] = useReducer(taskReducer, initialState);

    const addTask = useCallback((task) => dispatch({ type: 'ADD_TASK', payload: task }), [dispatch]);
    const setTasks = useCallback((tasks) => dispatch({ type: 'SET_TASKS', payload: tasks }), [dispatch]);
    const updateTask = useCallback((id, updates) => dispatch({ type: 'UPDATE_TASK', payload: { id, updates } }), [dispatch]);
    const toggleTaskStatus = useCallback((id) => dispatch({ type: 'TOGGLE_STATUS', payload: id }), [dispatch]);
    const postponeTask = useCallback((id, dueAt) => dispatch({ type: 'POSTPONE_TASK', payload: { id, dueAt } }), [dispatch]);
    const toggleReminder = useCallback((id, offset) => dispatch({ type: 'TOGGLE_REMINDER', payload: { id, offset } }), [dispatch]);
    const deleteTask = useCallback((id) => dispatch({ type: 'DELETE_TASK', payload: id }), [dispatch]);

    const updateRoutines = useCallback((routines) => dispatch({ type: 'UPDATE_ROUTINES', payload: routines }), [dispatch]);
    const toggleCategoryRoutines = useCallback((category) => dispatch({ type: 'TOGGLE_CAT_ROUTINES', payload: { category } }), [dispatch]);
    const updateUserSettings = useCallback((settings) => dispatch({ type: 'UPDATE_USER_SETTINGS', payload: settings }), [dispatch]);

    return {
        tasks: state.tasks,
        routines: state.routines,
        categorySettings: state.categorySettings,
        userSettings: state.userSettings,
        addTask,
