import { useState, useCallback, useRef, useEffect, useMemo } from 'react';

export function useVoice({ onTaskResult, onDeadlineResult, enableWakeWord = false, language = 'en' }) {
    const [isListening, setIsListening] = useState(false);
    const [status, setStatus] = useState('ready'); // ready, listening, processing, clarifying
    const [clarifyingTaskId, setClarifyingTaskId] = useState(null);
    const [transcript, setTranscript] = useState('');
    const recognitionRef = useRef(null);
    const timersRef = useRef({});

    // Use refs for callbacks and status to avoid re-initializing recognition
    const onTaskResultRef = useRef(onTaskResult);
    const onDeadlineResultRef = useRef(onDeadlineResult);
    const statusRef = useRef(status);

    useEffect(() => {
        onTaskResultRef.current = onTaskResult;
    }, [onTaskResult]);

    useEffect(() => {
        onDeadlineResultRef.current = onDeadlineResult;
    }, [onDeadlineResult]);

    useEffect(() => {
        statusRef.current = status;
    }, [status]);

    const speak = useCallback((text, listenAfter = false) => {
        if (!('speechSynthesis' in window)) return;
        window.speechSynthesis.cancel();
        const utterance = new SpeechSynthesisUtterance(text);

        // Map common codes to full tags for speechSynthesis
        const langMap = {
            'ru': 'ru-RU', 'en': 'en-US', 'de': 'de-DE', 'fr': 'fr-FR',
            'es': 'es-ES', 'zh': 'zh-CN', 'ja': 'ja-JP', 'ko': 'ko-KR',
            'it': 'it-IT', 'pt': 'pt-PT', 'ar': 'ar-SA', 'hi': 'hi-IN',
            'kk': 'kk-KZ', 'tr': 'tr-TR', 'vi': 'vi-VN', 'pl': 'pl-PL',
            'nl': 'nl-NL', 'id': 'id-ID', 'sv': 'sv-SE', 'bn': 'bn-BD'
        };
        utterance.lang = langMap[language] || 'en-US';
        utterance.onend = () => {
            if (listenAfter) {
                try {
                    recognitionRef.current?.start();
                } catch (e) {
                    console.warn("Recognition already started or error:", e);
                }
            }
        };
        window.speechSynthesis.speak(utterance);
    }, []);

    const stopAllTimers = useCallback((taskId) => {
        if (timersRef.current[taskId]) clearTimeout(timersRef.current[taskId]);
        if (timersRef.current[`${taskId}-retry`]) clearTimeout(timersRef.current[`${taskId}-retry`]);
        setClarifyingTaskId(null);
    }, []);

    const scheduleDeadlineAsk = useCallback((task) => {
        const { id, text } = task;

        // Timer A: 15 seconds
        const prompts = {
            en: [`Would you like to set a deadline for "${text}" now?`, `Reminder: What is the deadline for "${text}"?`, "I'm listening.", "Saved."],
            ru: [`Хочешь уточнить срок для "${text}" сейчас?`, `Напомни, какой срок у задачи: "${text}"?`, "Слушаю вас.", "Записала."],
            kk: [`"${text}" тапсырмасының мерзімін қазір көрсеткіңіз келе ме?`, `Еске саламын: "${text}" тапсырмасының мерзімі қандай?`, "Тыңдап тұрмын.", "Сақталды."]
        };
        const activePrompts = prompts[language] || prompts.en;

        timersRef.current[id] = setTimeout(() => {
            setStatus('clarifying');
            setClarifyingTaskId(id);
            speak(activePrompts[0], true);

            // Timer B: 5 minute follow-up
            timersRef.current[`${id}-retry`] = setTimeout(() => {
                setClarifyingTaskId(id);
                speak(activePrompts[1], true);
            }, 300000);
        }, 15000);
    }, [speak]);

    useEffect(() => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (!SpeechRecognition) return;

        const recognition = new SpeechRecognition();
        recognition.continuous = true;
        recognition.interimResults = true;
        const langMap = {
            'ru': 'ru-RU', 'en': 'en-US', 'de': 'de-DE', 'fr': 'fr-FR',
            'es': 'es-ES', 'zh': 'zh-CN', 'ja': 'ja-JP', 'ko': 'ko-KR',
            'it': 'it-IT', 'pt': 'pt-PT', 'ar': 'ar-SA', 'hi': 'hi-IN',
            'kk': 'kk-KZ', 'tr': 'tr-TR', 'vi': 'vi-VN', 'pl': 'pl-PL',
            'nl': 'nl-NL', 'id': 'id-ID', 'sv': 'sv-SE', 'bn': 'bn-BD'
        };
        recognition.lang = langMap[language] || 'en-US';

        recognition.onstart = () => {
            setIsListening(true);
            // Only promote to 'listening' when explicitly triggered (not wake-word passive mode)
            if (statusRef.current !== 'ready' || !enableWakeWord) {
                setStatus('listening');
            }
        };

        recognition.onend = () => {
            setIsListening(false);
            if (enableWakeWord && statusRef.current === 'ready') {
                try { recognition.start(); } catch (e) { }
            }
            setStatus(prev => prev === 'listening' ? 'ready' : prev);
        };

        recognition.onresult = (event) => {
            let currentTranscript = '';
            for (let i = event.resultIndex; i < event.results.length; ++i) {
                currentTranscript += event.results[i][0].transcript;
            }
            setTranscript(currentTranscript);

            if (statusRef.current === 'ready') {
                if (/bubble|бабл|бабы|көпіршік|көпір/i.test(currentTranscript)) {
                    const listenPrompt = language === 'ru' ? "Слушаю вас." : language === 'kk' ? "Тыңдап тұрмын." : "I'm listening.";
                    speak(listenPrompt);
                    setStatus('listening');
                    setTranscript('');
                    return;
                }
            }

            // Patience logic: Reset timer on every result (interim or final)
            if (timersRef.current.voiceSilenceTimer) clearTimeout(timersRef.current.voiceSilenceTimer);

            // Wait for 2 seconds of total silence before committing
            timersRef.current.voiceSilenceTimer = setTimeout(() => {
                const finalTranscript = currentTranscript.trim();

                if (finalTranscript) {
                    if (statusRef.current === 'listening' || statusRef.current === 'clarifying') {
                        setStatus('processing');
                        if (statusRef.current === 'clarifying') {
                            onDeadlineResultRef.current(finalTranscript);
                        } else {
                            onTaskResultRef.current(finalTranscript);
                            const savedPrompt = language === 'ru' ? "Записала." : language === 'kk' ? "Сақталды." : "Saved.";
                            speak(savedPrompt);
                        }
                    }
                }

                setTranscript('');
                try { recognition.stop(); } catch (e) { }
            }, 2000);
        };

        recognitionRef.current = recognition;

        if (enableWakeWord) {
            try { recognition.start(); } catch (e) { }
        }

        return () => {
            recognition.stop();
        };
    }, [speak, enableWakeWord, language]);

    const toggleListening = useCallback(() => {
        if (isListening) {
            recognitionRef.current?.stop();
            setStatus('ready');
        } else {
            // Explicitly set to 'listening' BEFORE starting recognition
            // so that onresult knows to treat speech as a task command
            setStatus('listening');
            try {
                recognitionRef.current?.start();
            } catch (e) {
                console.warn("Recognition already started:", e);
                // Even if recognition was already running, we want 'listening' mode
            }
        }
    }, [isListening]);

    return useMemo(() => ({
        isListening,
        status,
        transcript,
        clarifyingTaskId,
        toggleListening,
        speak,
        scheduleDeadlineAsk,
        stopAllTimers,
        setStatus,
        setClarifyingTaskId,
        setTranscript
    }), [
        isListening, status, transcript, clarifyingTaskId,
        toggleListening, speak, scheduleDeadlineAsk, stopAllTimers
    ]);
}

