export const CATEGORIES = [
    { name: 'Покупки', keywords: /куп|магаз|маркет|вкусвилл|еда|молоко|хлеб|buy|shop|grocery/i },
    { name: 'Работа', keywords: /раб|мит|звон|почт|встреч|колл|тикет|work|job|meet|call|email/i },
    { name: 'Дом', keywords: /дом|убор|посуд|стир|ремонт|home|house|clean|fix/i },
    { name: 'Здоровье', keywords: /врач|здор|аптек|таблет|спорт|зал|тренир|запись|прием|doctor|health|gym|sport|appointment|appoint|visit|кездесу/i },
    { name: 'Дети', keywords: /дет|ребен|сад|школ|урок|kids|child|school|lesson/i },
    { name: 'Финансы', keywords: /ден|банк|оплат|счет|карт|money|bank|pay|bill/i },
    { name: 'Общее', keywords: /.*/i }
];

export const parseTask = (text) => {
    const t = text.toLowerCase();

    // Category inference
    let category = 'Общее';
    for (const cat of CATEGORIES) {
        if (cat.keywords.test(t) && cat.name !== 'Общее') {
            category = cat.name;
            break;
        }
    }

    // Explicit category check (e.g., "для работы")
    const explicitMatch = text.match(/для\s+([а-яёA-Z0-9_-]+)/i);
    if (explicitMatch) {
        category = explicitMatch[1].charAt(0).toUpperCase() + explicitMatch[1].slice(1).toLowerCase();
    }

    // Simple deadline extraction
    let dueAt = null;
    const now = new Date();

    if (t.includes('сегодня') || t.includes('today')) {
        dueAt = new Date(now.setHours(23, 59, 0, 0)).getTime();
    } else if (t.includes('завтра') || t.includes('tomorrow')) {
        dueAt = new Date(now.setDate(now.getDate() + 1)).getTime();
        dueAt = new Date(dueAt).setHours(12, 0, 0, 0);
    }

    // Enhanced Time format (HH:MM or H часа дня/вечера/утра)
    const timeRegex = /(?:в\s+)?(\d{1,2})(?:[:.](\d{2}))?\s*(дня|вечера|утра|ночи)?/i;
    const timeMatch = text.match(timeRegex);

    if (timeMatch) {
        let hours = parseInt(timeMatch[1]);
        const minutes = timeMatch[2] ? parseInt(timeMatch[2]) : 0;
        const period = timeMatch[3] ? timeMatch[3].toLowerCase() : '';

        if ((period === 'дня' || period === 'вечера') && hours < 12) {
            hours += 12;
        } else if (period === 'утра' && hours === 12) {
            hours = 0;
        } else if (hours < 9 && !period) {
            // Heuristic: if someone says "at 3" without period, it's likely PM
            if (hours + 12 > now.getHours()) hours += 12;
        }

        const date = dueAt ? new Date(dueAt) : new Date();

        // If "tomorrow" was already found in text, ensure we are on the NEXT day
        if (t.includes('завтра')) {
            const tomorrow = new Date();
            tomorrow.setDate(tomorrow.getDate() + 1);
            date.setFullYear(tomorrow.getFullYear(), tomorrow.getMonth(), tomorrow.getDate());
        }

        date.setHours(hours, minutes, 0, 0);

        // If time is in the past and no period was specified, try PM
        // BUT don't do this if "tomorrow" is specified or if "morning/am" is specified
        const isMorning = period === 'утра' || period === 'am';
        if (date.getTime() < Date.now() && hours < 12 && !period && !t.includes('завтра') && !isMorning) {
            const pmDate = new Date(date.getTime());
            pmDate.setHours(hours + 12);
            if (pmDate.getTime() > Date.now()) {
                date.setHours(hours + 12);
            }
        }

        dueAt = date.getTime();
    }

    // Relative time "in N minutes"
    const inMatch = text.match(/через\s+(\d+)\s+(мин|час|дн)/i) || text.match(/in\s+(\d+)\s+(min|hour|day)/i);
    if (inMatch) {
        const amount = parseInt(inMatch[1]);
        const unit = inMatch[2].toLowerCase();
        const offset = unit.startsWith('м') || unit.startsWith('mi') ? amount * 60000
            : unit.startsWith('ч') || unit.startsWith('ho') ? amount * 3600000
                : amount * 86400000;
        dueAt = Date.now() + offset;
    }

    return {
        text: text.trim(),
        category,
        dueAt,
    };
};

