export const calculateBubbleStats = (tasks) => {
    const activeTasks = tasks.filter(t => t.status !== 'done');
    const count = activeTasks.length;

    let urgencyScore = 0;
    const now = Date.now();

    activeTasks.forEach(task => {
        if (task.dueAt) {
            const diff = task.dueAt - now;
            const hours = diff / 3600000;
            const days = hours / 24;

            if (hours <= 24) urgencyScore += 5;
            else if (days <= 3) urgencyScore += 3;
            else if (days <= 7) urgencyScore += 2;
            else urgencyScore += 1;
        } else {
            urgencyScore += 1;
        }
    });

    const baseSize = 78;
    const k1 = 5; // Urgency factor
    const k2 = 7; // Volume factor
    const minSize = 85;
    const maxSize = 160;

    const size = Math.min(maxSize, Math.max(minSize, baseSize + urgencyScore * k1 + count * k2));

    return { size, urgencyScore, openTaskCount: count };
};

export const formatTime = (ts) => {
    if (!ts) return 'No deadline';
    const now = Date.now();
    const diff = ts - now;
    const hours = diff / 3600000;
    const days = Math.floor(hours / 24);

    if (hours > 0 && hours < 24) {
        const itemDate = new Date(ts);
        const today = new Date();
        if (itemDate.getDate() !== today.getDate()) {
            return `Tomorrow, ${itemDate.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })}`;
        }
        return `Today, ${itemDate.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })}`;
    } else if (days >= 1 && days <= 30) {
        if (days === 1) {
            const itemDate = new Date(ts);
            return `Tomorrow, ${itemDate.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })}`;
        }
        return `${days} days`;
    }

    const date = new Date(ts);
    return date.toLocaleString('ru-RU', {
        month: 'short', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
    });
};
