export const getCategoryColor = (name) => {
    const categories = {
        'покупки': 'hsla(180, 100%, 70%, 0.6)',
        'работа': 'hsla(210, 100%, 70%, 0.6)',
        'дом': 'hsla(210, 100%, 60%, 0.4)',
        'здоровье': 'hsla(160, 100%, 60%, 0.4)',
        'дети': 'hsla(20, 100%, 70%, 0.4)',
        'финансы': 'hsla(45, 100%, 65%, 0.4)',
        'общее': 'hsla(240, 10%, 60%, 0.2)'
    };

    const lowerName = name.toLowerCase();
    if (categories[lowerName]) return categories[lowerName];

    // Generate a color based on the name hash for unknown categories
    let hash = 0;
    for (let i = 0; i < lowerName.length; i++) {
        hash = lowerName.charCodeAt(i) + ((hash << 5) - hash);
    }
    const hue = Math.abs(hash % 360);
    return `hsla(${hue}, 80%, 65%, 0.5)`;
};

