import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, Keyboard, Languages, Send, Sparkles, Camera, RefreshCw, X } from 'lucide-react';
import { WheelPicker } from './WheelPicker';
import { getTranslation } from '../translations';

export function TalkView({
    status, onToggleMic, onManualTask, isListening, onSmartSync, onOCRScan, syncStatus,
    transcript, pendingTask, onConfirmTask, onCancelPending, language
}) {
    const [showKeypad, setShowKeypad] = useState(false);
    const [inputValue, setInputValue] = useState('');

    const [selectedDate, setSelectedDate] = useState(new Date());
    const [editPendingText, setEditPendingText] = useState('');

    const handleSend = () => {
        if (inputValue.trim()) {
            onManualTask(inputValue);
            setInputValue('');
        }
    };

    useEffect(() => {
        if (pendingTask) {
            setEditPendingText(pendingTask.text);
            const initialDate = pendingTask.dueAt ? new Date(pendingTask.dueAt) : new Date();
            setSelectedDate(initialDate);
            setShowKeypad(false);
        }
    }, [pendingTask]);

    // Auto-confirm logic: 5 seconds of idleness
    useEffect(() => {
        if (pendingTask) {
            const timer = setTimeout(() => {
                onConfirmTask({
                    ...pendingTask,
                    text: editPendingText,
                    dueAt: selectedDate.getTime()
                });
            }, 5000);
            return () => clearTimeout(timer);
        }
    }, [pendingTask, editPendingText, selectedDate, onConfirmTask]);

    const days = Array.from({ length: 60 }, (_, i) => {
        const d = new Date();
        d.setDate(d.getDate() + i);
        if (i === 0) return getTranslation(language, 'today');
        if (i === 1) return getTranslation(language, 'tomorrow');
        return d.toLocaleDateString(language === 'ru' ? 'ru-RU' : language === 'kk' ? 'kk-KZ' : 'en-US', { day: 'numeric', month: 'short' });
    });

    const hours = Array.from({ length: 24 }, (_, i) => i.toString().padStart(2, '0'));
    const minutes = Array.from({ length: 12 }, (_, i) => (i * 5).toString().padStart(2, '0'));

    const handleWheelChange = (type, val) => {
        const newDate = new Date(selectedDate);
        if (type === 'day') {
            const index = days.indexOf(val);
            const targetDate = new Date();
            targetDate.setDate(targetDate.getDate() + index);
            newDate.setFullYear(targetDate.getFullYear(), targetDate.getMonth(), targetDate.getDate());
        } else if (type === 'hour') {
            newDate.setHours(parseInt(val));
        } else if (type === 'minute') {
            newDate.setMinutes(parseInt(val));
        }
        setSelectedDate(newDate);
    };

    return (
        <motion.section
            key="talk"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            className="talk-view"
        >
            <div className="greeting-container">
                <h2>{syncStatus ? 'Smart Sync' : status === 'clarifying' ? 'Clarifying Deadline' : pendingTask ? 'Confirm Task' : 'Ready for tasks'}</h2>
                <p>
                    {transcript || syncStatus || (status === 'listening' ? 'Listening...' : status === 'processing' ? 'Processing...' : 'Tap the button to talk')}
                </p>
            </div>

            <div className="mic-area">
                {pendingTask ? (
                    <motion.div
                        initial={{ y: 50, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        className="pending-review-card"
                    >
                        <div className="pending-field">
                            <label>Task</label>
                            <input
                                type="text"
                                className="edit-input"
                                value={editPendingText}
                                onChange={(e) => setEditPendingText(e.target.value)}
                            />
                        </div>

                        <div className="wheel-pickers-group">
                            <WheelPicker
                                label="Когда"
                                options={days}
                                value={
                                    selectedDate.toDateString() === new Date().toDateString() ? 'Сегодня' :
                                        selectedDate.toDateString() === new Date(Date.now() + 86400000).toDateString() ? 'Завтра' :
                                            selectedDate.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' })
                                }
                                onChange={(val) => handleWheelChange('day', val)}
                            />
                            <WheelPicker
                                label="Hour"
                                options={hours}
                                value={selectedDate.getHours().toString().padStart(2, '0')}
                                onChange={(val) => handleWheelChange('hour', val)}
                            />
                            <WheelPicker
                                label="Min"
                                options={minutes}
                                value={(Math.floor(selectedDate.getMinutes() / 5) * 5).toString().padStart(2, '0')}
                                onChange={(val) => handleWheelChange('minute', val)}
                            />
                        </div>

                        <div className="pending-actions">
                            <button className="cancel-pending" onClick={onCancelPending}>Cancel</button>
                            <button className="confirm-pending" onClick={() => onConfirmTask({
                                ...pendingTask,
                                text: editPendingText,
                                dueAt: selectedDate.getTime()
                            })}>OK, Add Task</button>
                        </div>
                    </motion.div>
                ) : (
                    <>
                        <button
                            className={`giant-mic-btn ${isListening ? 'active' : ''} ${syncStatus ? 'syncing' : ''}`}
                            onClick={onToggleMic}
                            disabled={!!syncStatus}
                        >
                            {syncStatus ? (
                                <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: "linear" }}>
                                    <Sparkles size={56} />
                                </motion.div>
                            ) : (
                                <Mic size={56} />
                            )}
                            {isListening && !syncStatus && (
                                <motion.div
                                    className="pulse-ring"
                                    animate={{ scale: [1, 1.4], opacity: [0.5, 0] }}
                                    transition={{ repeat: Infinity, duration: 1.5 }}
                                />
                            )}
                        </button>

                        <div className="aux-actions">
                            <button
                                className="action-btn"
                                onClick={onSmartSync}
                                title="Sync with Email, Notes & Calendar"
                            >
                                <RefreshCw size={20} />
                                <span>Sync Hub</span>
                            </button>

                            <button
                                className="action-btn"
                                onClick={onOCRScan}
                                title="Scan handwritten text"
                            >
                                <Camera size={20} />
                                <span>Scan</span>
                            </button>

                            <button
                                className={`action-btn ${showKeypad ? 'active' : ''}`}
                                onClick={() => setShowKeypad(!showKeypad)}
                                title="Type task manually"
                            >
                                <Keyboard size={20} />
                                <span>{getTranslation(language, 'type')}</span>
                            </button>
                        </div>
                    </>
                )}
            </div>

            <AnimatePresence>
                {showKeypad && !pendingTask && (
                    <motion.div
                        initial={{ y: 100, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        exit={{ y: 100, opacity: 0 }}
                        className="keypad-input-area"
                    >
                        <button className="keypad-tool-btn" onClick={onToggleMic} title="Voice input" style={{ width: '32px', height: '32px' }}>
                            <Mic size={14} />
                        </button>
                        <input
                            type="text"
                            placeholder={getTranslation(language, 'typeYourTask')}
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                            autoFocus
                        />
                        <button className="send-btn" onClick={handleSend} style={{ width: '32px', height: '32px' }}><Send size={14} /></button>
                        <button className="keypad-tool-btn" onClick={() => setShowKeypad(false)} style={{ marginLeft: '4px', width: '32px', height: '32px' }}>
                            <X size={10} />
                        </button>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.section>
    );
}

