                                                    <button onClick={() => { handleEditStart(task); setActionsExpandedId(null); }} className="shade-action-btn" title="Edit"><Pencil size={13} /></button>
                                                    <button onClick={() => { setRepeatingId(repeatingId === task.id ? null : task.id); setActionsExpandedId(null); }} className="shade-action-btn" title="Repeat"><RotateCcw size={13} /></button>
                                                    <button onClick={() => { setPostponingId(postponingId === task.id ? null : task.id); setActionsExpandedId(null); }} className="shade-action-btn" title="Postpone"><Clock size={13} /></button>
                                                    <button onClick={() => { setReminderId(reminderId === task.id ? null : task.id); setActionsExpandedId(null); }} className={`shade-action-btn ${reminderId === task.id ? 'active' : ''}`} title="Remind"><Bell size={13} /></button>
                                                    <button onClick={() => { onShareTasks([task]); setActionsExpandedId(null); }} className="shade-action-btn" title="Share"><Share2 size={13} /></button>
                                                    <button onClick={() => { handleDelete(task.id); setActionsExpandedId(null); }} className="shade-action-btn trash-btn" title="Delete"><Trash2 size={13} /></button>
                                                </div>
                                            </div>
                                        )}
                                        <button
                                            onClick={() => effectiveBulkMode ? onSelectTask(task.id) : onToggleTask(task.id)}
                                            className="status-toggle status-toggle-right"
                                        >
                                            {effectiveBulkMode ? (
                                                effectiveSelectedIds.includes(task.id)
                                                    ? <CheckSquare size={18} color={effectiveBulkMode === 'delete' ? '#ef4444' : "var(--accent-primary)"} />
                                                    : <Square size={18} />
                                            ) : (
                                                task.status === 'done'
                                                    ? <CheckSquare size={18} color="#10b981" />
                                                    : <Square size={18} />
                                            )}
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    );
                })}
            </div>

            {bulkMode === 'share' && (
                <div style={{ position: 'fixed', bottom: '100px', left: '50%', transform: 'translateX(-50%)', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px', zIndex: 1000 }}>
                    <button className="big-action-btn" onClick={() => onShareTasks(tasks.filter(t => localSelectedTasks.includes(t.id)))}>
                        <Share2 size={20} />
                        <span>Share Selected ({localSelectedTasks.length})</span>
                    </button>
                    <button
                        className="cancel-btn"
                        style={{ background: 'rgba(255,255,255,0.1)', backdropFilter: 'blur(20px)', borderRadius: '20px', padding: '8px 20px', fontSize: '0.8rem', border: 'none', color: '#fff', cursor: 'pointer' }}
                        onClick={() => { setBulkMode(null); setLocalSelectedTasks([]); }}
                    >
                        Cancel Selection
                    </button>
                </div>
            )}

            {bulkMode === 'delete' && (
                <div style={{ position: 'fixed', bottom: '100px', left: '50%', transform: 'translateX(-50%)', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px', zIndex: 1000 }}>
                    <button className="big-action-btn delete" onClick={handleDeleteSelected}>
                        <Trash2 size={20} />
                        <span>Delete Selected ({localSelectedTasks.length})</span>
                    </button>
                    <button
                        className="cancel-btn"
                        style={{ background: 'rgba(255,255,255,0.1)', backdropFilter: 'blur(20px)', borderRadius: '20px', padding: '8px 20px', fontSize: '0.8rem', border: 'none', color: '#fff', cursor: 'pointer' }}
                        onClick={() => { setBulkMode(null); setLocalSelectedTasks([]); }}
                    >
                        Cancel Selection
                    </button>
                </div>
            )}
        </motion.div>
    );
}

// Stable seeded pseudo-random so positions don't change on re-render
function seededRand(seed, offset = 0) {
    const s = Math.sin(seed * 127.1 + offset * 311.7) * 43758.5453;
    return s - Math.floor(s);
}

function BubbleItem({ bubble, onClick, index, totalCount, language }) {
    const { size, openTaskCount } = bubble;

    const { left, top, blobRadius, swimX, swimY, swimDur } = useMemo(() => {
        const COLS = 2;
        const ROWS = Math.ceil(Math.max(totalCount, 1) / COLS);

        const col = index % COLS;
        const row = Math.floor(index / COLS);

        // Cell size as percentages of the container
        const cellW = 100 / COLS;          // 50%
        const cellH = 88 / ROWS;           // distribute vertically (leave 12% top padding)

        // Centre of the cell + mild seeded jitter (max ±12% of cell size)
        const jX = (seededRand(index, 0) * 2 - 1) * cellW * 0.12;
        const jY = (seededRand(index, 1) * 2 - 1) * cellH * 0.12;

        const left = cellW * col + cellW / 2 + jX;
        const top = 6 + cellH * row + cellH / 2 + jY;

        // Gentle swim drift — only ±8px so bubbles never escape their cell
        const swimX = [
            0,
            (seededRand(index, 2) * 2 - 1) * 8,
            (seededRand(index, 3) * 2 - 1) * 8,
            0,
        ];
        const swimY = [
            0,
            (seededRand(index, 4) * 2 - 1) * 8,
            (seededRand(index, 5) * 2 - 1) * 8,
            0,
        ];
        const swimDur = 10 + seededRand(index, 6) * 6;

        // Organic blob shape
        const r = (v) => Math.round(30 + seededRand(index, v) * 40);
        const blobRadius = `${r(7)}% ${r(8)}% ${r(9)}% ${r(10)}% / ${r(11)}% ${r(12)}% ${r(13)}% ${r(14)}%`;

        return { left, top, blobRadius, swimX, swimY, swimDur };
    }, [index, totalCount]);

    return (
        <motion.div
            animate={{ x: swimX, y: swimY, rotate: [0, (seededRand(index, 15) * 2 - 1) * 3, 0] }}
            transition={{ duration: swimDur, repeat: Infinity, ease: 'easeInOut' }}
            drag
            dragElastic={0.08}
            whileHover={{ scale: 1.06, zIndex: 20 }}
            whileTap={{ scale: 0.94 }}
            onClick={onClick}
            className={`task-bubble blob-shape category-${(bubble.name || 'general').toLowerCase()}`}
            style={{
                width: size,
                height: size,
                borderRadius: blobRadius,
                background: getCategoryColor(bubble.name),
                border: '1px solid rgba(255,255,255,0.15)',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                backdropFilter: 'blur(12px)',
                position: 'absolute',
                cursor: 'pointer',
                left: `calc(${left}% - ${size / 2}px)`,
                top: `calc(${top}%  - ${size / 2}px)`,
                textAlign: 'center',
                padding: '10px',
                boxShadow: '0 8px 32px rgba(0,0,0,0.25)',
            }}
        >
            <div className="bubble-content" style={{ pointerEvents: 'none' }}>
                <h4 style={{ margin: 0, fontSize: '0.85rem', color: '#fff', textShadow: '0 2px 6px rgba(0,0,0,0.4)', fontWeight: 700 }}>
                    {getCategoryName(language, bubble.name)}
                </h4>
                <div style={{ fontSize: '0.68rem', color: 'rgba(255,255,255,0.75)', marginTop: '4px' }}>
                    {openTaskCount} tasks
                </div>
            </div>
        </motion.div>
    );
}

