} from 'lucide-react';
import { formatTime } from '../utils';
import { TaskIcon } from './TaskIcon';
import { getTranslation, getCategoryName } from '../translations';

const iconMap = { Sun, Activity, Coffee, Droplets, Heart, Phone };

function DeadlineBlock({ dueAt }) {
    if (!dueAt) return <td className="task-deadline-col task-deadline-empty">—</td>;
    const d = new Date(dueAt);
    const hr = String(d.getHours()).padStart(2, '0');
    const min = String(d.getMinutes()).padStart(2, '0');
    const day = d.getDate();
    const mon = d.toLocaleDateString([], { month: 'short' }).replace('.', '');
    const isOverdue = dueAt < Date.now();
    return (
        <td className={`task-deadline-col ${isOverdue ? 'overdue' : ''}`}>
            <div className="dl-inner">
                <span className="dl-time">{hr}:{min}</span>
                <span className="dl-date">{day} {mon}</span>
            </div>
        </td>
    );
}


export function BubbleDetailModal({
    bubble, onClose, onToggleTask, onPostponeTask, onShareTask, onUpdateTask, onDeleteTask, onSetTasks, allTasks = [], onToggleReminder, onAddTask,
