    const [confirmPending, setConfirmPending] = useState(null); // null | 'selected' | 'all' | taskId

    const DAYS = language === 'ru' ? ['Пн', 'Вт', 'Ср', 'Чт', 'Пт', 'Сб', 'Вс'] : language === 'kk' ? ['Дс', 'Сс', 'Ср', 'Бс', 'Жм', 'Сн', 'Жк'] : ['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su'];

    const handleAddTask = () => {
        if (!newTaskText.trim()) return;
        onAddTask({
            id: Date.now().toString(),
            text: newTaskText,
            category: bubble.name,
            status: 'open',
            createdAt: Date.now(),
