        setEditValue(task.text);
    };

    const handleEditSave = (id) => {
        onUpdateTask(id, { text: editValue });
        setEditingId(null);
    };

    const handlePostponeSave = (id, dateStr) => {
        const dueAt = dateStr ? new Date(dateStr).getTime() : Date.now() + 86400000 * 10;
        onPostponeTask(id, dueAt);
        setPostponingId(null);
    };

    const handleDelete = (id) => {
        onDeleteTask(id);
        if (editingId === id) setEditingId(null);
    };

    const handleSelectAll = () => {
