        setSelectedTaskIds(prev =>
            prev.includes(id) ? prev.filter(tid => tid !== id) : [...prev, id]
        );
    };

    const handleShareSelected = () => {
        const selectedTasks = bubble.tasks.filter(t => selectedTaskIds.includes(t.id));
        onShareTask(selectedTasks);
        setBulkMode(null);
        setSelectedTaskIds([]);
