        setConfirmPending(null);
    };

    const getTimelineTime = (item) => {
        try {
            if (item.type === 'routine') {
                const startTime = item.startTime || '00:00';
                const parts = startTime.split(':');
                if (parts.length === 2) {
                    const [h, m] = parts;
                    const d = new Date();
                    d.setHours(parseInt(h) || 0, parseInt(m) || 0, 0, 0);
                    return d.getTime();
                }
                return 0;
            }
            return item.dueAt || item.createdAt || Date.now();
        } catch (e) {
            return Date.now();
        }
    };

    const filteredTasks = bubble.tasks.filter(t =>
        t.text.toLowerCase().includes(localSearchQuery.toLowerCase())
    );

    const combinedList = [
        ...filteredTasks.map(t => ({ ...t, type: 'task' })),
        ...(showRoutines ? routines.map(r => ({ ...r, type: 'routine' })) : [])
