        const getStatusPriority = (item) => {
            if (item.type === 'routine') return 0;
            const statusOrder = { open: 0, half: 0, postponed: 2, done: 3 };
            return statusOrder[item.status] ?? 0;
        };

        const prioA = getStatusPriority(a);
