import React, { useEffect, useRef } from 'react';

export function NotificationManager({ tasks }) {
    const notifiedRef = useRef({});

    useEffect(() => {
        if (!("Notification" in window)) return;

        if (Notification.permission === "default") {
            Notification.requestPermission();
        }

        const interval = setInterval(() => {
            const now = Date.now();
            tasks.forEach(task => {
                if (task.status === 'done' || !task.dueAt) return;

                const diffMinutes = Math.floor((task.dueAt - now) / 60000);

                // Check if any specified reminder offset matches current diff
                const reminders = task.reminders || [5, 30, 60];

                reminders.forEach(offset => {
                    const key = `${task.id}-${offset}`;
                    // Trigger if we are exactly at the offset or slightly past it (within 1 min)
                    if (diffMinutes === offset && !notifiedRef.current[key]) {
                        showNotification(task, offset);
                        notifiedRef.current[key] = true;
                    }
                });
            });
        }, 30000); // Check every 30 seconds

        return () => clearInterval(interval);
    }, [tasks]);

    const showNotification = (task, offset) => {
        if (Notification.permission === "granted") {
            const label = offset >= 60 ? `${offset / 60}h` : `${offset}m`;
            new Notification("Bubble Notification", {
                body: `${task.text} is due in ${label}!`,
                icon: "/pwa-192x192.png" // Fallback or app icon
            });
        }
    };

    return null; // Side-effect only component
}

