import React, { useRef, useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Camera, RefreshCw, Check, Sparkles, Image as ImageIcon } from 'lucide-react';
import Tesseract from 'tesseract.js';

export function ScanModal({ onClose, onScanComplete }) {
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const [stream, setStream] = useState(null);
    const [isScanning, setIsScanning] = useState(false);
    const [progress, setProgress] = useState(0);
    const [error, setError] = useState(null);
    const [capturedImage, setCapturedImage] = useState(null);
    const fileInputRef = useRef(null);

    useEffect(() => {
        startCamera();
        return () => {
            if (stream) {
                stream.getTracks().forEach(track => track.stop());
            }
        };
    }, []);

    const startCamera = async () => {
        try {
            const mediaStream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'environment' },
                audio: false
            });
            setStream(mediaStream);
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream;
            }
        } catch (err) {
            console.error("Camera error:", err);
            setError("Could not access camera. Please check permissions.");
        }
    };

    const handleCapture = async () => {
        if (!videoRef.current || isScanning) return;

        const video = videoRef.current;
        const canvas = canvasRef.current;
        const context = canvas.getContext('2d');

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);

        const imageData = canvas.toDataURL('image/jpeg');
        setCapturedImage(imageData);
        performOCR(imageData);
    };

    const handleFileUpload = (e) => {
        const file = e.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            const imageData = event.target.result;
            setCapturedImage(imageData);
            performOCR(imageData);
        };
        reader.readAsDataURL(file);
    };

    const performOCR = async (image) => {
        setIsScanning(true);
        setProgress(0);
        setError(null);

        try {
            const { data: { text } } = await Tesseract.recognize(
                image,
                'rus+eng',
                {
                    logger: m => {
                        if (m.status === 'recognizing text') {
                            setProgress(m.progress);
                        }
                    }
                }
            );

            if (text.trim()) {
                onScanComplete(text.trim());
            } else {
                setError("No text recognized. Try again with better lighting.");
                setIsScanning(false);
                setCapturedImage(null);
            }
        } catch (err) {
            console.error("OCR error:", err);
            setError("Error processing image.");
            setIsScanning(false);
            setCapturedImage(null);
        }
    };

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="modal-backdrop"
            style={{ zIndex: 2000 }}
        >
            <motion.div
                initial={{ y: "100%" }}
                animate={{ y: 0 }}
                exit={{ y: "100%" }}
                className="scan-modal-content"
                style={{
                    position: 'absolute',
                    bottom: 0,
                    left: 0,
                    right: 0,
                    height: '90%',
                    background: '#0a0a0a',
                    borderTopLeftRadius: '30px',
                    borderTopRightRadius: '30px',
                    display: 'flex',
                    flexDirection: 'column',
                    overflow: 'hidden'
                }}
            >
                <div className="modal-header" style={{ padding: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
                    <h3 style={{ margin: 0, display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <Camera size={20} className="text-accent" />
                        Scan Task
                    </h3>
                    <button onClick={onClose} className="close-btn" style={{ background: 'rgba(255,255,255,0.1)', border: 'none', color: '#fff', padding: '8px', borderRadius: '50%' }}>
                        <X size={20} />
                    </button>
                </div>

                <div className="scan-viewport" style={{ flex: 1, position: 'relative', background: '#000' }}>
                    {capturedImage ? (
                        <img src={capturedImage} style={{ width: '100%', height: '100%', objectFit: 'contain' }} alt="Captured" />
                    ) : (
                        <video
                            ref={videoRef}
                            autoPlay
                            playsInline
                            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                        />
                    )}

                    <canvas ref={canvasRef} style={{ display: 'none' }} />

                    <div className="scan-overlay" style={{
                        position: 'absolute',
                        top: '50%',
                        left: '50%',
                        transform: 'translate(-50%, -50%)',
                        width: '80%',
                        height: '30%',
                        border: '2px solid var(--accent-primary)',
                        borderRadius: '20px',
                        boxShadow: '0 0 0 9999px rgba(0,0,0,0.5)',
                        pointerEvents: 'none'
                    }}>
                        <div className="scan-line" />
                    </div>

                    {isScanning && (
                        <div className="scanning-ui" style={{
                            position: 'absolute',
                            inset: 0,
                            background: 'rgba(0,0,0,0.7)',
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '20px'
                        }}>
                            <motion.div
                                animate={{ rotate: 360 }}
                                transition={{ repeat: Infinity, duration: 2, ease: "linear" }}
                            >
                                <RefreshCw size={48} className="text-accent" />
                            </motion.div>
                            <div style={{ textAlign: 'center' }}>
                                <p style={{ margin: 0, fontSize: '1.2rem', fontWeight: 'bold' }}>Recognizing Text...</p>
                                <div style={{ width: '200px', height: '4px', background: 'rgba(255,255,255,0.1)', borderRadius: '2px', marginTop: '10px', overflow: 'hidden' }}>
                                    <motion.div
                                        style={{ height: '100%', background: 'var(--accent-primary)' }}
                                        animate={{ width: `${progress * 100}%` }}
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    {error && (
                        <div className="error-ui" style={{
                            position: 'absolute',
                            bottom: '100px',
                            left: '20px',
