const iconMap = { Sun, Activity, Coffee, Droplets, Heart, Phone };

export function SettingsModal({ settings, routines, onUpdate, onUpdateRoutines, onClose, onLogout }) {
    const [activeTab, setActiveTab] = useState('appearance'); // appearance, routines

    const handleAddRoutine = () => {
        const newRoutine = {
            id: Date.now().toString(),
            text: 'New Routine',
            icon: 'Sun',
            startTime: '09:00',
            endTime: '10:00'
        };
        onUpdateRoutines([...routines, newRoutine]);
    };

    const handleUpdateRoutine = (id, updates) => {
        const newRoutines = routines.map(r => r.id === id ? { ...r, ...updates } : r);
        onUpdateRoutines(newRoutines);
    };

    const handleDeleteRoutine = (id) => {
        onUpdateRoutines(routines.filter(r => r.id !== id));
    };

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="modal-backdrop"
            onClick={onClose}
        >
            <motion.div
                initial={{ y: 100, scale: 0.95 }}
                animate={{ y: 0, scale: 1 }}
                exit={{ y: 100, scale: 0.95 }}
                className="modal-content settings-modal-modern"
                onClick={e => e.stopPropagation()}
            >
                <div className="modal-header">
                    <div className="settings-tabs">
                        <button
                            className={`tab-btn ${activeTab === 'appearance' ? 'active' : ''}`}
