                        >
                            {getTranslation(settings.language, 'routines')}
                        </button>
                        <button
                            className={`tab-btn ${activeTab === 'language' ? 'active' : ''}`}
                            onClick={() => setActiveTab('language')}
                        >
                            {getTranslation(settings.language, 'language')}
                        </button>
                    </div>
                    <button onClick={onClose} className="close-btn"><X size={12} /></button>
                </div>

                <div className="settings-scroll-area">
                    {activeTab === 'appearance' && (
                        <motion.div
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="tab-content"
                        >
                            <div className="settings-section">
                                <label><Palette size={16} /> {getTranslation(settings.language, 'accentColor')}</label>
                                <div className="color-grid">
                                    {colors.map(c => (
                                        <div
                                            key={c.value}
                                            className={`color-option-row ${settings.accentColor === c.value ? 'active' : ''}`}
                                            onClick={() => onUpdate({ accentColor: c.value })}
                                        >
                                            <div className="color-swatch-sm" style={{ backgroundColor: c.value }} />
                                            <span className="color-name" style={{ color: c.value, fontWeight: 'bold' }}>{c.name}</span>
                                            {settings.accentColor === c.value && <Check size={14} color={c.value} />}
                                        </div>
                                    ))}
                                </div>
                            </div>
                            <div className="settings-section">
                                <label><Sun size={16} /> {getTranslation(settings.language, 'theme')}</label>
                                <div className="theme-toggle-group">
                                    <button
                                        className={`theme-btn ${settings.theme === 'light' ? 'active' : ''}`}
                                        onClick={() => onUpdate({ theme: 'light' })}
                                    >
                                        <Sun size={14} /> {getTranslation(settings.language, 'light')}
                                    </button>
                                    <button
                                        className={`theme-btn ${settings.theme === 'dark' || !settings.theme ? 'active' : ''}`}
                                        onClick={() => onUpdate({ theme: 'dark' })}
                                    >
                                        <Moon size={14} /> {getTranslation(settings.language, 'dark')}
                                    </button>
                                </div>
                            </div>

                            <div className="settings-section">
                                <label><Type size={16} /> {getTranslation(settings.language, 'fontFamily')}</label>
                                <div className="font-list">
                                    {fonts.map(f => (
                                        <button
                                            key={f.value}
                                            className={`font-item ${settings.fontFamily === f.value ? 'active' : ''}`}
                                            style={{ fontFamily: f.value }}
                                            onClick={() => onUpdate({ fontFamily: f.value })}
                                        >
                                            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start' }}>
                                                <span style={{ fontSize: '1rem' }}>{f.name}</span>
                                                <span style={{ fontSize: '0.7rem', opacity: 0.6 }}>The quick brown fox jumps over the lazy dog (Abc)</span>
                                            </div>
                                            {settings.fontFamily === f.value && <Check size={14} />}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className="settings-section">
                                <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                        <Sun size={18} />
                                        <span>{getTranslation(settings.language, 'enableDailyRoutines')}</span>
                                    </div>
                                    <input
                                        type="checkbox"
                                        checked={settings?.enableDailyRoutines}
                                        onChange={(e) => onUpdate({ enableDailyRoutines: e.target.checked })}
                                        style={{ width: '20px', height: '20px', cursor: 'pointer' }}
                                    />
                                </label>
                            </div>

                            <div className="settings-section">
                                <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                        <Activity size={16} />
                                        <span>{getTranslation(settings.language, 'voiceActivation')}</span>
                                    </div>
                                    <input
                                        type="checkbox"
                                        checked={settings?.voiceActivation}
                                        onChange={(e) => onUpdate({ voiceActivation: e.target.checked })}
                                        style={{ width: '20px', height: '20px', cursor: 'pointer' }}
                                    />
                                </label>
                                <p style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', marginTop: '4px' }}>
                                    {getTranslation(settings.language, 'experimental')}
                                </p>
                            </div>
                        </motion.div>
                    )}

                    {activeTab === 'routines' && (
                        <motion.div
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="tab-content"
                        >
                            <div className="routines-editor-list">
                                {routines.map(routine => {
                                    const IconNode = iconMap[routine.icon] || Sun;
                                    return (
                                        <div key={routine.id} className="routine-edit-card">
                                            <div className="routine-edit-header">
                                                <div className="icon-selector-dropdown">
                                                    <IconNode size={20} />
                                                    <select
                                                        value={routine.icon}
                                                        onChange={(e) => handleUpdateRoutine(routine.id, { icon: e.target.value })}
                                                    >
                                                        {Object.keys(iconMap).map(iconName => (
                                                            <option key={iconName} value={iconName}>{iconName}</option>
                                                        ))}
                                                    </select>
                                                </div>
                                                <input
                                                    className="routine-text-input"
                                                    value={routine.text}
                                                    onChange={(e) => handleUpdateRoutine(routine.id, { text: e.target.value })}
                                                    placeholder={getTranslation(settings.language, 'routineName')}
                                                />
                                                <button
                                                    className="delete-routine-btn"
                                                    onClick={() => handleDeleteRoutine(routine.id)}
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                            <div className="routine-time-inputs">
                                                <div className="time-input-group">
                                                    <Clock size={14} />
                                                    <input
                                                        type="time"
                                                        value={routine.startTime}
                                                        onChange={(e) => handleUpdateRoutine(routine.id, { startTime: e.target.value })}
                                                    />
                                                    <span>{getTranslation(settings.language, 'to')}</span>
                                                    <input
                                                        type="time"
                                                        value={routine.endTime}
                                                        onChange={(e) => handleUpdateRoutine(routine.id, { endTime: e.target.value })}
                                                    />
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}

                                <button className="add-routine-btn" onClick={handleAddRoutine}>
                                    <Plus size={18} /> {getTranslation(settings.language, 'addNewRoutine')}
                                </button>
                            </div>
                        </motion.div>
                    )}

                    {activeTab === 'language' && (
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className="tab-content"
                        >
                            <div className="settings-section">
                                <label><Languages size={16} /> {getTranslation(settings.language, 'appLanguage')}</label>
                                <div className="font-list">
                                    {commonLanguages.map(lang => (
                                        <button
                                            key={lang.code}
                                            className={`font-item ${settings.language === lang.code ? 'active' : ''}`}
                                            onClick={() => onUpdate({ language: lang.code })}
                                        >
                                            {lang.name}
                                            {settings.language === lang.code && <Check size={14} />}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    )}
                </div>

                <div className="settings-footer">
                    <button className="logout-btn" onClick={onLogout}>
                        <LogOut size={16} /> Logout
                    </button>
                </div>
            </motion.div>
        </motion.div>
    );
}

