import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Send, Copy, Mail, MessageCircle, Facebook, Twitter, Linkedin, Slack, Disc as Discord, Instagram, Share2 } from 'lucide-react';
import { getTranslation } from '../translations';

export function ShareModal({ isOpen, onClose, tasks, language }) {
    if (!isOpen) return null;

    const taskText = tasks.map(t => {
        const statusIcon = t.status === 'done' ? '✅' : t.status === 'half' ? '🌗' : '⭕️';
        const deadline = t.dueAt ? ` (${getTranslation(language, 'due')}: ${new Date(t.dueAt).toLocaleDateString()})` : '';
        return `${statusIcon} ${t.text}${deadline}`;
    }).join('\n');

    const fullText = `${getTranslation(language, 'shareTasks')}:\n\n${taskText}`;
    const encodedText = encodeURIComponent(fullText);
    const encodedUrl = encodeURIComponent(window.location.href);

    const shareOptions = [
        { name: 'WhatsApp', icon: <MessageCircle size={24} color="#25D366" />, url: `https://wa.me/?text=${encodedText}` },
        { name: 'Telegram', icon: <Send size={24} color="#0088cc" />, url: `https://t.me/share/url?url=${encodedUrl}&text=${encodedText}` },
        { name: 'Facebook', icon: <Facebook size={24} color="#1877F2" />, url: `https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}&quote=${encodedText}` },
        { name: 'X (Twitter)', icon: <Twitter size={24} color="#000000" />, url: `https://twitter.com/intent/tweet?text=${encodedText}` },
        { name: 'LinkedIn', icon: <Linkedin size={24} color="#0A66C2" />, url: `https://www.linkedin.com/sharing/share-offsite/?url=${encodedUrl}` },
        { name: 'Slack', icon: <Slack size={24} color="#4A154B" />, url: `slack://share?text=${encodedText}` },
        { name: 'Discord', icon: <Discord size={24} color="#5865F2" />, url: `https://discord.com/channels/@me` }, // Discord doesn't have a great web share URL
        { name: 'Instagram', icon: <Instagram size={24} color="#E4405F" />, url: `https://www.instagram.com/` },
        { name: 'Email', icon: <Mail size={24} color="#ea4335" />, url: `mailto:?subject=My Tasks&body=${encodedText}` },
        { name: 'TikTok', icon: <div style={{ width: 24, height: 24, background: '#000', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '10px', fontWeight: 'bold', color: '#fff' }}>TT</div>, url: `https://www.tiktok.com/` },
        {
            name: 'More', icon: <Share2 size={24} color="#666" />, action: () => {
                if (navigator.share) {
                    navigator.share({ title: 'Tasks', text: fullText }).catch(() => { });
                } else {
                    handleCopy();
                }
            }
        },
    ];

    const handleCopy = () => {
        navigator.clipboard.writeText(fullText);
        alert(getTranslation(language, 'sharedToClipboard'));
    };

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="modal-overlay"
                onClick={onClose}
                style={{ zIndex: 2000 }}
            >
                <motion.div
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 200 }}
                    className="share-sheet"
                    onClick={(e) => e.stopPropagation()}
                >
                    <div className="share-header">
                        <h3>{getTranslation(language, 'shareTasks')}</h3>
                        <button onClick={onClose} className="close-btn"><X size={12} /></button>
                    </div>

                    <div className="share-grid">
                        {shareOptions.map((opt) => (
                            opt.url ? (
                                <a key={opt.name} href={opt.url} target="_blank" rel="noopener noreferrer" className="share-option">
                                    <div className="share-icon-wrapper">
                                        {opt.icon}
                                    </div>
                                    <span className="share-label">{opt.name}</span>
                                </a>
                            ) : (
                                <button key={opt.name} onClick={opt.action} className="share-option" style={{ background: 'none', border: 'none', padding: 0, cursor: 'pointer' }}>
                                    <div className="share-icon-wrapper">
                                        {opt.icon}
                                    </div>
                                    <span className="share-label">{opt.name}</span>
                                </button>
                            )
                        ))}
                    </div>

                    <div className="share-footer">
                        <button onClick={handleCopy} className="copy-full-btn">
                            <Copy size={18} />
                            <span>{getTranslation(language, 'copyText')}</span>
                        </button>
                    </div>
                </motion.div>
            </motion.div>
        </AnimatePresence>
    );
}

