import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, RefreshCw, Mail, Calendar, FileText, Check, AlertCircle, Sparkles, ArrowRight } from 'lucide-react';

export function SyncHubModal({ onClose, onSync }) {
    const [syncingSources, setSyncingSources] = useState([]);
    const [results, setResults] = useState([]);
    const [isFinished, setIsFinished] = useState(false);

    const sources = [
        { id: 'gmail', name: 'Gmail', icon: Mail, color: '#ea4335', description: 'Analyze recent task-related emails' },
        { id: 'calendar', name: 'Google Calendar', icon: Calendar, color: '#4285f4', description: 'Fetch events for the next 7 days' },
        { id: 'notes', name: 'Apple Notes', icon: FileText, color: '#fbbc05', description: 'Extract tasks from shared notes' }
    ];

    const startSync = async () => {
        setSyncingSources(sources.map(s => s.id));
        setResults([]);
        setIsFinished(false);

        // Simulate syncing one by one
        for (const source of sources) {
            await new Promise(r => setTimeout(r, 1500));
            let newTasks = [];
            if (source.id === 'gmail') {
                newTasks = [
                    { id: 'g1', text: 'Confirm design meeting', category: 'Work', dueAt: Date.now() + 3600000 },
                    { id: 'g2', text: 'Pick up parcel from Piatyorochka', category: 'Shopping', dueAt: Date.now() + 86400000 }
                ];
            } else if (source.id === 'calendar') {
                newTasks = [
                    { id: 'c1', text: 'Kids morning party', category: 'Kids', dueAt: Date.now() + 172800000 }
                ];
            } else if (source.id === 'notes') {
                newTasks = [
                    { id: 'n1', text: 'Buy vitamins', category: 'Health' }
                ];
            }

            setResults(prev => [...prev, { sourceId: source.id, tasks: newTasks }]);
            setSyncingSources(prev => prev.filter(id => id !== source.id));
        }

        setIsFinished(true);
    };

    const handleConfirm = () => {
        const allTasks = results.flatMap(r => r.tasks);
        onSync(allTasks);
        onClose();
    };

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="modal-backdrop"
            style={{ zIndex: 2000 }}
        >
            <motion.div
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0.9, opacity: 0 }}
                className="sync-hub-modal"
                style={{
                    width: '90%',
                    maxWidth: '400px',
                    background: 'rgba(13, 13, 13, 0.95)',
                    backdropFilter: 'blur(30px)',
                    borderRadius: '30px',
                    border: '1px solid rgba(255,255,255,0.1)',
                    padding: '24px',
                    display: 'flex',
                    flexDirection: 'column',
                    gap: '20px',
                    boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)'
                }}
            >
                <div className="modal-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ padding: '8px', background: 'var(--accent-primary)', borderRadius: '12px' }}>
                            <RefreshCw size={20} color="white" />
                        </div>
                        <h3 style={{ margin: 0 }}>Sync Hub</h3>
                    </div>
                    <button onClick={onClose} style={{ background: 'transparent', border: 'none', color: 'rgba(255,255,255,0.5)', cursor: 'pointer' }}>
                        <X size={24} />
                    </button>
                </div>

                {!isFinished && syncingSources.length === 0 && results.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '20px 0' }}>
                        <div style={{ width: '80px', height: '80px', borderRadius: '50%', background: 'rgba(255,255,255,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px' }}>
                            <Sparkles size={40} className="text-accent" />
                        </div>
                        <p style={{ opacity: 0.7, marginBottom: '24px' }}>AI will analyze your accounts to suggest new tasks automatically.</p>
                        <button
                            onClick={startSync}
                            className="big-action-btn"
                            style={{ position: 'static', transform: 'none', width: '100%' }}
                        >
                            Start Intelligence Sync
                        </button>
                    </div>
                ) : (
                    <div className="sync-sources-list" style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                        {sources.map(source => {
                            const isSyncing = syncingSources.includes(source.id);
                            const result = results.find(r => r.sourceId === source.id);
                            const Icon = source.icon;

                            return (
                                <div
                                    key={source.id}
                                    style={{
                                        background: 'rgba(255,255,255,0.05)',
                                        borderRadius: '16px',
                                        padding: '16px',
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '15px',
                                        border: isSyncing ? `1px solid ${source.color}` : '1px solid transparent',
                                        transition: 'all 0.3s ease'
                                    }}
                                >
                                    <div style={{ padding: '10px', background: `${source.color}22`, borderRadius: '12px', color: source.color }}>
                                        <Icon size={24} />
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <div style={{ fontWeight: 'bold', fontSize: '0.95rem' }}>{source.name}</div>
                                        <div style={{ fontSize: '0.75rem', opacity: 0.5 }}>{source.description}</div>
                                    </div>
                                    <div style={{ width: '40px', display: 'flex', justifyContent: 'center' }}>
                                        {isSyncing ? (
                                            <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: 'linear' }}>
                                                <RefreshCw size={20} className="text-accent" />
                                            </motion.div>
                                        ) : result ? (
                                            <div style={{ color: '#10b981', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                                                <Check size={20} />
                                                <span style={{ fontSize: '0.6rem', fontWeight: 'bold' }}>+{result.tasks.length}</span>
                                            </div>
                                        ) : null}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}

                {isFinished && (
                    <motion.div
                        initial={{ y: 20, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        style={{ marginTop: '10px' }}
                    >
                        <div style={{ padding: '16px', background: 'rgba(16, 185, 129, 0.1)', borderRadius: '16px', border: '1px solid rgba(16, 185, 129, 0.2)', marginBottom: '20px' }}>
                            <div style={{ fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px', color: '#10b981' }}>
                                <Sparkles size={16} />
                                AI Found {results.reduce((acc, r) => acc + r.tasks.length, 0)} Tasks
                            </div>
                            <p style={{ fontSize: '0.8rem', opacity: 0.7, margin: '8px 0 0' }}>These tasks were extracted and prioritized based on your habits.</p>
                        </div>
                        <button
                            onClick={handleConfirm}
                            className="big-action-btn"
                            style={{ position: 'static', transform: 'none', width: '100%' }}
                        >
                            Accept & Add to Bubbles
                        </button>
                    </motion.div>
                )}
            </motion.div>

            <style>{`
                .sync-hub-modal .big-action-btn {
                    background: var(--accent-primary);
                    color: white;
                    border: none;
                    border-radius: 16px;
                    padding: 16px;
                    font-weight: bold;
                    cursor: pointer;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    gap: 10px;
                    box-shadow: 0 10px 20px rgba(var(--accent-primary-rgb), 0.3);
                }
                .text-accent { color: var(--accent-primary); }
            `}</style>
        </motion.div>
    );
}

