import React, { useRef, useEffect, useState, useCallback } from 'react';

export function WheelPicker({ options, value, onChange, label }) {
    const scrollRef = useRef(null);
    const itemHeight = 44;
    const [activeIndex, setActiveIndex] = useState(options.indexOf(value));

    useEffect(() => {
        if (scrollRef.current) {
            const initialIndex = options.indexOf(value);
            scrollRef.current.scrollTop = initialIndex * itemHeight;
        }
    }, [options, value]);

    const handleScroll = useCallback(() => {
        if (!scrollRef.current) return;
        const scrollTop = scrollRef.current.scrollTop;
        const index = Math.round(scrollTop / itemHeight);

        if (index >= 0 && index < options.length) {
            setActiveIndex(index);
            if (options[index] !== value) {
                onChange(options[index]);
            }
        }
    }, [options, value, onChange]);

    return (
        <div className="wheel-picker-container">
            {label && <span className="wheel-label">{label}</span>}
            <div className="wheel-viewport" style={{ height: itemHeight * 5 }}>
                <div
                    className="wheel-scroll"
                    ref={scrollRef}
                    onScroll={handleScroll}
                >
                    <div className="wheel-list">
                        <div style={{ height: itemHeight * 2 }} />
                        {options.map((opt, i) => {
                            const distance = Math.abs(i - activeIndex);
                            // Sharper opacity drop-off to avoid "ghosting" background clutter
                            const opacity = distance === 0 ? 1 : Math.max(0, 0.4 - distance * 0.15);
                            const scale = distance === 0 ? 1.05 : 1 - distance * 0.05;
                            const rotation = (i - activeIndex) * 25;

                            return (
                                <div
                                    key={i}
                                    className={`wheel-item ${i === activeIndex ? 'selected' : ''}`}
                                    style={{
                                        height: itemHeight,
                                        lineHeight: `${itemHeight}px`,
                                        opacity,
                                        transform: `scale(${scale}) rotateX(${rotation}deg)`,
                                        transition: 'transform 0.15s cubic-bezier(0.2, 0, 0.2, 1), opacity 0.15s',
                                        letterSpacing: '0.01em',
                                        fontSize: opt.length > 8 ? '0.9rem' : 'inherit',
                                        whiteSpace: 'nowrap'
                                    }}
                                >
                                    {opt}
                                </div>
                            );
                        })}
                        <div style={{ height: itemHeight * 2 }} />
                    </div>
                </div>
                <div className="wheel-glass-highlight" style={{ height: itemHeight, top: itemHeight * 2 }} />
            </div>
        </div>
    );
}
